from langgraph.types import Command


def researcher_v2(state: HandoffState) -> Command:
    task = state["messages"][-1].content
    response = llm_fast.invoke(f"Research:\n{task}")
    return Command(
        update={
            "messages": [AIMessage(content=response.content, name="researcher")],
            "context": {**state["context"], "research": response.content},
        },
        goto="analyst",  # explicit handoff target
    )


def analyst_v2(state: HandoffState) -> Command:
    research = state["context"].get("research", "")
    response = llm_fast.invoke(f"Analyse:\n{research}")
    return Command(
        update={
            "messages": [AIMessage(content=response.content, name="analyst")],
            "context": {**state["context"], "analysis": response.content},
        },
        goto="writer",
    )


def writer_v2(state: HandoffState) -> Command:
    analysis = state["context"].get("analysis", "")
    response = llm_strong.invoke(f"Write summary:\n{analysis}")
    return Command(
        update={
            "messages": [AIMessage(content=response.content, name="writer")],
            "result": response.content,
        },
        goto=END,
    )

from langchain_core.tools import tool
from langchain_core.messages import ToolMessage
from langchain_anthropic import ChatAnthropic


@tool
def handoff_to_researcher(reason: str) -> str:
    """Transfer to the Researcher agent. Use when information gathering is needed."""
    return f"Handing off to researcher: {reason}"


@tool
def handoff_to_analyst(reason: str) -> str:
    """Transfer to the Analyst agent. Use when data analysis or comparison is needed."""
    return f"Handing off to analyst: {reason}"


@tool
def handoff_to_writer(reason: str) -> str:
    """Transfer to the Writer agent. Use when producing the final output."""
    return f"Handing off to writer: {reason}"


orchestrator_llm = ChatAnthropic(model="claude-sonnet-5").bind_tools(
    [handoff_to_researcher, handoff_to_analyst, handoff_to_writer]
)


def llm_orchestrator(state: HandoffState) -> Command:
    response = orchestrator_llm.invoke(state["messages"])
    # Extract the tool call to determine the next agent
    if response.tool_calls:
        tool_name = response.tool_calls[0]["name"]
        agent_map = {
            "handoff_to_researcher": "researcher",
            "handoff_to_analyst": "analyst",
            "handoff_to_writer": "writer",
        }
        next_agent = agent_map.get(tool_name, "writer")
        return Command(
            update={"messages": [response], "active_agent": next_agent},
            goto=next_agent,
        )
    # No tool call — orchestrator produced a final answer directly
    return Command(
        update={"messages": [response], "result": response.content},
        goto=END,
    )

