def researcher_safe(state: HandoffState) -> Command:
    try:
        task = state["messages"][-1].content
        response = llm_fast.invoke(f"Research:\n{task}")
        return Command(
            update={
                "messages": [AIMessage(content=response.content, name="researcher")],
                "context": {**state["context"], "research": response.content},
            },
            goto="analyst",
        )
    except Exception as exc:
        # Record error in context; hand off to a fallback agent
        error_msg = AIMessage(
            content=f"Researcher failed: {exc}. Falling back to writer with partial data.",
            name="researcher",
        )
        return Command(
            update={
                "messages": [error_msg],
                "context": {**state["context"], "error": str(exc)},
            },
            goto="writer",   # skip analyst; writer handles graceful degradation
        )
